INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028543e3c98b0941766232', '由于去年入住体验不错，外地朋友今次来广州，再次点名入住花园酒店。
办理入住很有效率，Tony还为我们送了花，心情都好起来了[呲牙]
房间设施很好，但床垫和沙发都偏软，不太舒服。
酒廊出品依然不错，服务也很好，最深印象是Esther，还有个靓女我没看清名字。另外发现一个之前很酸的甜品这次好吃多了。如果点心和甜品品种能定期换一下或者有更多选择就好了。
瀑布餐厅拍照真的很漂亮
退房时有问我们入住体验，当然是很满意。
在大堂遇到酒店的金牌导游，热情介绍了周边的的景点和博物馆，好面善，看回以前的评价原来是去年也赞过的Yannis，好巧啊。朋友说下次来还住花园', '["https://dimg04.c-ctrip.com/images/0230712000be7iyamE0CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000be7ktkm7C0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000be7krfq568A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000be7gfxa92C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-11', '城央绿意双床房', '双床房', '朋友出游', 277, 0, 4, 9, '["整体满意度","房间设施","餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施'),
('68028543e3c98b0941766235', '每年春节旅游必住之地', '["https://dimg04.c-ctrip.com/images/0231612000aqbw49l0F79_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-02', '花园大床房', '大床房', '家庭亲子', 10, 0, 21, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028543e3c98b0941766236', '干净卫生，服务态度好', '["https://dimg04.c-ctrip.com/images/0237212000ahp1alv4DB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000ahp17moDB5A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-23', '花园大床房', '大床房', '家庭亲子', 10, 0, 8, 3, '["卫生状况","前台服务"]'::jsonb, '卫生状况', '前台服务', NULL),
('68028543e3c98b0941766238', '非常好的酒店', '["https://dimg04.c-ctrip.com/images/0230e12000ai52o7j1638_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000ai52lcn06F2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-25', '红棉大床套房', '套房', '家庭亲子', 6, 0, 2, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028543e3c98b0941766249', '前台小姐姐小鱼服务非常好，主动，热情，亲和力强，房间布局，合理、干净，无异味、床品很舒服，淋浴出水也很快，早餐劵停车票都有，房间干净入住首选值得推荐??。大堂迎宾服务不错LiVen??', '["https://dimg04.c-ctrip.com/images/0231z12000jgum5x162A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000jgsijys70C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000jgt2crbF8B9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-01', '花园大床房', '大床房', '家庭亲子', 92, 0, 10, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028543e3c98b094176625a', '酒店文化气息丰富，装饰细节处处彰显，从LILI管家到客房中心小何、行政酒廊服务ECHO，每个服务人员都非常认真可亲，对客人有问必答，事事有回应，件件都落实。我的体验感真是无比亲切！下次还来，提一嘴酒店的博物馆做得很好呢！', '["https://dimg04.c-ctrip.com/images/0235012000f6ibw6qBFAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000f6ik1pj3A8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000f6hxp9r6C37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-19', '花园双床房', '双床房', '家庭亲子', 110, 0, 11, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68028543e3c98b0941766271', '特别感谢rain妹妹，特别漂亮的一个小妹妹，每次都是提前准备好，这次是家人过来住，家人对房间很满意，40多年的老店能保持这么好，理地位置也不错，出门就是地铁，还有博物馆，里面还有8个餐厅，都不用出去吃，拍照也是很好看，服务态度那就不用说了，真的很人性化，我个人还是很喜欢的。', '["https://dimg04.c-ctrip.com/images/0235g12000awu8iga17A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000awu8trlFD37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000awu97021808_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-11', '花园双床房', '双床房', '家庭亲子', 137, 0, 2, 8, '["整体满意度","交通便利性","周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套'),
('68028543e3c98b0941766276', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，这个价格入住这个酒店真的是超值，下次有机会一定会再来，停车方便，入住很快，房间也比较舒适，价格不贵，环境也不错，房间干净，入住首选，满意！特别感谢迎宾李文。前台Viria', '["https://dimg04.c-ctrip.com/images/0236x12000jgqv957DDF1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000jgrrk2q150D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-01', '花园大床房', '大床房', '独自旅行', 125, 0, 1, 6, '["整体满意度","卫生状况","性价比"]'::jsonb, '整体满意度', '卫生状况', '性价比'),
('68028543e3c98b094176627d', '酒店被鲜花绿树环绕，大堂富丽堂皇，前台susan微笑服务，操作熟练，办理入住快，安排房间满意。房间亮敞、ROSS打扫房间干净整洁无死角，且服务好。泳池环境好，服务好。瀑布旁吃早餐很惬意，品种繁多，环境好，服务好。参观了四楼博物馆，非常好，很多图片，实物完整了解酒店业的发展，长知识。总机接线员卢小姐，沟通能力强，处理问题暖心。', '["https://dimg04.c-ctrip.com/images/0233m12000cfn2ibtD645_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000cfn0s98C795_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000cfn1yzfEE31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000cfn36mnFB42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000cfn1he13CE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000cfn1yzhE33C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000cfn0uql9714_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000cfn442z4E80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000cfn28k8A72C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-22', '红棉大床套房', '套房', '朋友出游', 163, 0, 160, 9, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68028543e3c98b0941766286', '超赞的一家酒店！！！酒店房间温馨，酒店装修氛围太棒了，光照合适，不让人感觉有压力，床品超级舒服，旅游一天的累躺下就想不起来了，卫生干净，服务贼棒！！！酒店服务热情，卫生干净整洁，房间温馨宽敞，酒店位置优越，房间的价格也很实惠，性价比高！得到的不止一次舒适愉悦的入住体验，还有人间烟火，这是我对这家酒店的评价。超赞！也特别谢谢rain。酒店旋转自助餐推荐哦??', '["https://dimg04.c-ctrip.com/images/0231512000jpf71nn43BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000jpgs5agC953_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000jpfhlpsB938_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000jpf5q40234A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-10', '花园大床房', '大床房', '朋友出游', 179, 0, 1, 8, '["整体满意度","房间设施","性价比"]'::jsonb, '整体满意度', '房间设施', '性价比'),
('68028543e3c98b0941766289', '这次入住体验很满意，各方面服务都很好，kamille的服务很棒，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0234312000b8la2ybBBCE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-17', '红棉大床套房', '套房', '商务出差', 39, 0, 6, 5, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68028543e3c98b094176628a', '房间设施齐全，服务人员素质高，，跟一些快捷商务酒店很不一样。早餐品种丰富，房间设施新，床品舒服，总体物超所值，是一次非常满意的体验。可加床，门口可停车，离多条地铁站近，步行七八分钟。离高铁站机场七八公里。', '["https://dimg04.c-ctrip.com/images/0231g12000app31qt97C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000app227c6327_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000amriw5gD8F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-25', '城央绿意双床房', '双床房', '商务出差', 102, 0, 59, 7, '["房间设施","整体满意度","交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性'),
('68028543e3c98b094176628c', '服务很好 去的时候赶上春节 小马办理入住退房都很热情 清扫阿姨还给了小福袋 早餐很丰盛 后面的小花园饭后散散步很舒服 酒店旁边就是地铁 出行非常的方便', '["https://dimg04.c-ctrip.com/images/0234q12000ahp0wrn7940_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000ahp3v4eCC26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000ahp3qbuF7A7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-23', '城央绿意大床房', '大床房', '情侣出游', 75, 0, 36, 8, '["前台服务","餐饮设施","交通便利性"]'::jsonb, '前台服务', '餐饮设施', '交通便利性'),
('68028543e3c98b094176628e', '房间真的很棒，服务也特别特别好。进来酒店就感觉很大气，前台savanna小姐姐的服务也是超级好！很贴心并且长的很漂亮也很感谢她！冲着她的服务下次来还是会选择这家酒店！很值得！', '["https://dimg04.c-ctrip.com/images/0234412000cnej4af6A9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000cnehhg8AEA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-28', '红棉大床套房', '套房', '独自旅行', 87, 0, 5, 7, '["前台服务","整体满意度","性价比"]'::jsonb, '前台服务', '整体满意度', '性价比'),
('68028543e3c98b0941766291', '设施：大厅环境很好，让人眼前一亮。装修豪华，还有瀑布餐厅。
房间设施：有好喝的咖啡，和好喝的茶。床上用品很舒服，枕头很软（本人很喜欢）
卫生：打扫的很干净，没有异味。
服务：
小邓还送了我们免费的早餐，给了我们大大的惊喜。超级开心??', '["https://dimg04.c-ctrip.com/images/0236a12000evew8v3B7DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000evezkmr5A56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000eves78f9A5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000evf1yi59F87_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000evf4qvo28E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000eveyt507177_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000evf08gyCD05_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-07-23', '花园双床房', '双床房', '独自旅行', 117, 0, 7, 7, '["房间设施","餐饮设施","卫生状况"]'::jsonb, '房间设施', '餐饮设施', '卫生状况'),
('68028543e3c98b0941766292', '花园酒店是我出差广州的必选酒店。位置好。而且最关键的是它的后花园，环境真的超舒服。里头的水池锦鲤，亭宇楼阁。美不胜收。最难得的就是前台服务Betty小姐，服务超好，细致耐心且十分礼貌。是一次绝佳的体验。[强][强][强]', '["https://dimg04.c-ctrip.com/images/0235l12000aqs3tflE845_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000aqsbof3E039_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000aqs9m6b08B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000aqsat7iA4C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000aqs2el78B47_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000aqs4j28A178_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000aqs3j607F19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000aqsbhgz9ABF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000aqs80zq0FA4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '花园大床房', '大床房', '商务出差', 110, 0, 26, 8, '["前台服务","整体满意度","周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套'),
('68028543e3c98b094176629a', '酒店非常大 设施完善 健身房相对简单 但是基本可以满足需求 泳池没有开放看上去不错，谢谢客服Maggie帮助我升级到顶层套房 房间设计风格中式现代 干净 地理位置附近好吃的也很好找， 推荐家庭旅行 推荐商务旅行。 餐厅景色独具一格 是广州非常好的国际化现代酒店。 早餐非常丰富 推荐享用', '["https://dimg04.c-ctrip.com/images/0230r12000apkbz7dF976_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000apkd1995666_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-24', '城央绿意大床房', '大床房', '家庭亲子', 143, 0, 7, 8, '["公共设施","整体满意度","餐饮设施"]'::jsonb, '公共设施', '整体满意度', '餐饮设施'),
('68028543e3c98b094176629e', '过年非常热闹，人很多，服务人员训练有素，有经验的进行询问引导。环境还是这么好，大气又精致，朋友家人来穗首选酒店。热心的前台管家Cathy还送一支漂亮??，非常开心！', '["https://dimg04.c-ctrip.com/images/0230512000ajhul8q3A55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000ajhpq0k2E56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000ajhu76iB92A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-30', '花园大床房', '大床房', '朋友出游', 82, 0, 4, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028543e3c98b094176629f', '位置一流！去哪都不远，附近好吃的很多。
设施一流！酒店里就有三个米其林，样样好吃。
服务一流！前台管家小洪非常热情，其它部门客房，礼宾部，门卫，服务都很主动。
非常棒的入住体验，下次来一定还住这里！', '["https://dimg04.c-ctrip.com/images/0234v12000asgqw5p2B5B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000asgsephF927_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000asgnrfa3397_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000asghvne1494_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-19', '城央绿意双床房', '双床房', '朋友出游', 99, 0, 4, 9, '["周边配套","餐饮设施","前台服务"]'::jsonb, '周边配套', '餐饮设施', '前台服务'),
('68028543e3c98b09417662a0', '酒店周围郁郁葱葱的花园营造出宁静的氛围，非常适合放松身心。工作人员非常友好和细心，确保满足我们的所有需求。房间宽敞、设备齐全，可欣赏到城市的壮丽景色。酒店内的餐饮选择多样而美味，可满足所有口味。此外，酒店位置便利，方便探索当地景点。我强烈推荐所有来广州的客人入住花园酒店！', '["https://dimg04.c-ctrip.com/images/0236r324x90cnuwqtA87E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-05', '城央绿意大床房', '大床房', '朋友出游', 136, 0, 48, 9, '["整体满意度","景观/朝向","餐饮设施"]'::jsonb, '整体满意度', '景观/朝向', '餐饮设施'),
('68028543e3c98b09417662a1', '我最喜爱的酒店??', '["https://dimg04.c-ctrip.com/images/0232t12000j73jinvAC8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000j73mzv64D02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-20', '红棉大床套房', '套房', '商务出差', 9, 0, 52, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028543e3c98b09417662a2', '地方舒适，环境卫生，服务员态度和蔼亲切。往后来广州都住这。', '["https://dimg04.c-ctrip.com/images/0233s224x8yp80qo5EC16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a224x8yp93tp5FF34_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-18', '城央绿意双床房', '双床房', '家庭亲子', 29, 0, 3, 5, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028543e3c98b09417662a3', '这次已经是我们的第二十多次入住花园酒店了，酒店的优雅格局和保养依然是很好！而且房间仍然是保持得很好，很卫生和干净 非常的舒适！
而适逢入住期间是中秋佳节，酒店很贴心地送了我们一盒很精美的月饼。我们感到非常的窝心！如果下次再回来广州出差或游玩，花园酒店仍然会我们的首选！！', '["https://dimg04.c-ctrip.com/images/0231g224x8wfhdji27BB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q224x8wfidnyq9942_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 135, 0, 4, 8, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028543e3c98b09417662a9', '酒店出门几百米就有地铁，出行非常方便，早餐有三个餐厅可以选择，30楼的旋转餐厅和1楼的瀑布餐厅以及3楼的桃源馆都很棒，推荐升级套房住会舒服些，在花园酒店可以感受到浓郁的岭南风情与外地文化，还有酒店的博物馆也是很值得打卡的，酒店的工作人员都很nice，但是吧缺点就是隔音不好，入住时遇到楼上亲子家庭的晚上8点开始吵闹蹦蹦跳跳，早上7点半开始蹦蹦跳跳，吵到人怀疑人生的那种就挺无奈的吧！！！！', '["https://dimg04.c-ctrip.com/images/0230512000fgiv5x2D598_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000fgigkre22C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000fgia37n6F70_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000fgihdtiC087_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000fgiddxu8668_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000fgif00976A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000fgis8u94983_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000fgih6btB01F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000fgirway3C1C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-08', '花园大床房', '大床房', '朋友出游', 194, 0, 5, 9, '["交通便利性","餐饮设施","安静程度"]'::jsonb, '交通便利性', '餐饮设施', '安静程度'),
('68028543e3c98b09417662aa', '环境不错????', '["https://dimg04.c-ctrip.com/images/02321224x90n99g89052D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2025-04-15', '城央绿意双床房', '双床房', '家庭亲子', 8, 0, 25, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028543e3c98b09417662ab', '这是我们回国第二次入住花园酒店,我们预订了5天；办理入住的前台玲玲负责接待我们,她的服务态度非常好,解释清晰,非常细心,办理入住手续快捷，安排的房间在13楼房间干净整洁,客房部清洁人员非常勤快,每天准时清洁房间卫生，服务态度也是超好的,总体客房部表现不错??
我们在酒店尝试了不同的美食,从桃园馆的早餐,至午餐的荔湾亭还有晚餐的瀑布餐厅的自助餐,最后还有已经二次光顾的「庭」日本餐厅，当然回广州还有点外卖??
点评一下餐饮部；早茶的点心中规中矩,不足的地方是虾饺皮较厚,肉质较柴，萝卜糕很好吃??
荔湾亭出品;价格跟品质对等,出餐快「因为我们需要赶车去香港转飞机，所以需要40分钟内吃完」部长也快速完成任务,赞一个??
瀑布餐厅自助餐;出品满意,食物品种多样,主管Joanna 非常贴心,细致, 餐后会细心询问客人的意见与满意度,这是非常难得的????
最后是日本餐厅「庭」;这是我第二次光顾他们,经理与客服人员服务一如既往的5星,食物需要改进的部份是天妇罗, 天妇罗的粉浆调的稍浓,所以导致上浆过厚, 口感不够松化。
Ps:酒店也贴心的安置了外卖柜在酒店内中国银行的旁边??如果想喝啤酒,也可以在酒店附设的小卖店购买,我购买了3瓶Asahi辛口啤酒,15元一瓶,「价格合理」折汇后价格跟加拿大酒行卖的同价。', '["https://dimg04.c-ctrip.com/images/0231n224x8vul45n46B06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02321224x8vukneuu98DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n224x8vul87sy8647_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f224x8vukbdhs9632_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02360224x8vukcdtb6064_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s224x8vuk23c17ADB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o224x8vulxm9cA736_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p224x8vultqsz8097_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m224x8vujwgul4BB8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-06', '花园双床房', '双床房', '家庭亲子', 554, 0, 3, 9, '["餐饮设施","前台服务","客房服务"]'::jsonb, '餐饮设施', '前台服务', '客房服务'),
